"use strict";const initializeThemeSwitcherEnvironment=()=>{const e=document.documentElement,t=document.getElementById("themeToggleBtn");let n=!1;t.addEventListener("click",()=>{n=!n,n?(e.setAttribute("data-theme","dark"),t.textContent="Switch to Light Mode",console.log("Dark mode has been enabled successfully.")):(e.removeAttribute("data-theme"),t.textContent="Switch to Dark Mode",console.log("Light mode has been enabled successfully."))})};document.addEventListener("DOMContentLoaded",initializeThemeSwitcherEnvironment);